//FHQ-Treap
#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5,P=31,mod=1e9+9;

struct Node{
    int val,dat;
    int h,siz;
    int l,r;
}a[N];

int m,tot,root,mi[N];

int New(char val){
	tot++;
    a[tot].val=a[tot].h=val-'a'+1,a[tot].dat=rand();
    a[tot].siz=1;
    return tot;
}

void Update(int p){
    if(!p)
        return;
    a[p].h=(1LL*mi[1+a[a[p].r].siz]*a[a[p].l].h+1LL*mi[a[a[p].r].siz]*a[p].val+a[a[p].r].h)%mod;
    a[p].siz=a[a[p].l].siz+1+a[a[p].r].siz;
}

int merge(int p,int q){
    if(!p)
        return q;
    if(!q)
        return p;
    if(a[p].dat>a[q].dat){
        a[p].r=merge(a[p].r,q);
        Update(a[p].r),Update(p);
        return p;
    }else{
        a[q].l=merge(p,a[q].l);
        Update(a[q].l),Update(q);
        return q;
    }
}

pair<int,int> split(int p,int k){
    if(k==a[p].siz)
        return make_pair(p,0);
    if(!k)
        return make_pair(0,p);
    pair<int,int> tmp;
    if(k<=a[a[p].l].siz){
        tmp=split(a[p].l,k);
        a[p].l=tmp.second,Update(a[p].l),Update(p);
        return make_pair(tmp.first,p);
    }else{
        tmp=split(a[p].r,k-a[a[p].l].siz-1);
        a[p].r=tmp.first,Update(a[p].r),Update(p);
        return make_pair(p,tmp.second);
    }
}

void dfs(int p){
	if(!p)
		return;
	dfs(a[p].l);
	printf("%c",a[p].val+'a'-1);
	dfs(a[p].r);
}

void output(int l,int r){
	pair<int,int> tmp=split(root,l-1);
    int x=tmp.first;
    tmp=split(tmp.second,r-l+1);
    dfs(tmp.first);
    puts("");
    root=merge(x,merge(tmp.first,tmp.second)); 
}

int cal(int l,int r){
    pair<int,int> tmp=split(root,l-1);
    int x=tmp.first,res;
    tmp=split(tmp.second,r-l+1);
    res=a[tmp.first].h;
    root=merge(x,merge(tmp.first,tmp.second));
    return res;
}

int main(){
    mi[0]=1;
    for(int i=1;i<N;i++)
        mi[i]=1LL*mi[i-1]*P%mod;
    srand(time(NULL));
    char s[N];
    scanf("%s",s+1);
    int len=strlen(s+1);
    for(int i=1;i<=len;i++)
        root=merge(root,New(s[i]));
    scanf("%d",&m);
    while(m--){
        char op[2];
        int x;
        scanf("%s%d",op,&x);
        if(op[0]=='Q'){
            int y;
            scanf("%d",&y);
            int l=0,r=min(tot-x,tot-y)+1;
            while(l<r){
                int mid=l+r+1>>1;
                if(cal(x,x+mid-1)==cal(y,y+mid-1))
                    l=mid;
                else
                    r=mid-1;
            }
            printf("%d\n",l);
        }else if(op[0]=='R'){
            char d[2];
            scanf("%s",d);
            pair<int,int> tmp=split(root,x-1);
            int x=tmp.first,y,z;
            tmp=split(tmp.second,1);
            y=tmp.first,z=tmp.second;
            a[y].val=a[y].h=d[0]-'a'+1;
            root=merge(merge(x,y),z);
        }else{
            char d[2];
            scanf("%s",d);
            pair<int,int> tmp=split(root,x);
            root=merge(tmp.first,merge(New(d[0]),tmp.second));
        }
    }
    return 0;
}
